};

export default function UserProfile() {
  const [user, setUser] = useState(null);
  const [savedArticles, setSavedArticles] = useState([]);
  const [savedResult, setSavedResult] = useState(null);
  const [descOpen, setDescOpen] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem("auth_token");
    if (token) {
      const payload = JSON.parse(atob(token.split(".")[1]));
      setUser(payload);
    }

    const articles = JSON.parse(localStorage.getItem("savedArticles")) || [];
    setSavedArticles(articles);

    const result = localStorage.getItem("savedResult");
    setSavedResult(result);
  }, []);

  const removeArticle = (slug) => {
    const updated = savedArticles.filter(a => a.slug !== slug);
    setSavedArticles(updated);
    localStorage.setItem("savedArticles", JSON.stringify(updated));
  };

  const removeResult = () => {
    setSavedResult(null);
    localStorage.removeItem("savedResult");
    setDescOpen(false);
  };

  if (!user) return null;

  return (
    <section className="profile-page">
      <div className="profile-left">
        <img src={user.photo} alt={user.email} className="profile-avatar" />
        <span className="profile-email">{user.email}</span>
      </div>

      {savedResult && (
        <div className="saved-result">
          <div className="saved-result-header">
            <h3>შენი ტესტის შედეგი</h3>
            <img
              src="/save1.png"
              alt="remove"
              className="remove-icon-result"
              onClick={removeResult}
            />
          </div>
          <img
            src={`/images/types/${savedResult}.png`}
            width="120"
            alt={savedResult}
          />
          <p className={`test-description ${descOpen ? "open" : ""}`}>
            {typeDescriptions[savedResult]}
          </p>
          <span
            className="toggle-desc"
            onClick={() => setDescOpen(!descOpen)}
          >
            {descOpen ? "დაკეცვა ▲" : "გახსნა ▼"}
          </span>
        </div>
      )}

      <div className="saved-section">
        <h3>შენახული სტატიები</h3>
        <div className="saved-cards">
          {savedArticles.map((a) => (
            <div key={a.slug} className="saved-card-container">
              <Link to={`/articles/${a.slug}`} className="saved-card">
                <img
                  src={a.image ? `/images/${a.image}` : "/images/default.png"}
                  alt={a.title}
                  className="saved-card-image"
                />
                <p className="saved-card-title">{a.title}</p>
              </Link>
              <img
                src="/images/remove-icon.png"
                className="remove-icon-card"
                alt="remove"
                onClick={() => removeArticle(a.slug)}
              />
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
